module top_module(
  input [3:0] data_in,
  input shift_in,
  input load,
  input clk,
  output reg [3:0] data_out
);reg [3:0] invalid_shift_reg;

  always @(posedge clk) begin
    if (load) begin
      invalid_shift_reg <= data_in;
    end else begin
      invalid_shift_reg <= {invalid_shift_reg[2:0], shift_in};
    end
  end

  assign data_out = invalid_shift_reg;

endmodule
